	secondDir := t.TempDir()
	runGitInteg(t, secondDir, "clone", originDir, ".")
	runGitInteg(t, secondDir, "config", "user.email", "test@ddx.test")
	runGitInteg(t, secondDir, "config", "user.name", "DDx Test")
